import React, { useState } from "react";
import {
  //AspectRatio,
  Box,
  Button,
  //ButtonGroup,
  //Center,
  Checkbox,
  //Container,
  Divider,
  //Flex,
  FormControl,
  //FormLabel,
  //FormErrorMessage,
  //FormHelperText,
  //Grid,
  //GridItem,
  Heading,
  HStack,
  //Icon,
  //IconButton,
  //Image,
  Input,
  InputGroup,
  InputLeftAddon,
  //InputLeftElement,
  //Modal,
  //ModalOverlay,
  //ModalContent,
  //ModalHeader,
  //ModalFooter,
  //ModalBody,
  //ModalCloseButton,
  //Radio,
  //RadioGroup,
  Select,
  //SimpleGrid,
  //Stack,
  //StackDivider,
  Text,
  //Tabs,
  useDisclosure,
} from "@chakra-ui/react";
//import * as emailjs from "emailjs-com";
//import { useRecoilState } from "recoil";
//import { loginLevelState } from "./data/atomdata";
import { makeStyles } from "@material-ui/core/styles";
//import { useCustomToast } from "../helpers/useCustomToast";
//import { useEmployees } from "./employees/useEmployees";
import { useHoc } from "./hoc/useHoc";
import { Controller, useForm } from "react-hook-form";
import Export2Excel from "./Export2Excel";

const initial_state = {
  type: "",
  month: new Date().getMonth(),
  year: new Date().getFullYear(),
  filename: "",
};

const months = [
  { name: "January" },
  { name: "February" },
  { name: "March" },
  { name: "April" },
  { name: "May" },
  { name: "June" },
  { name: "July" },
  { name: "August" },
  { name: "September" },
  { name: "October" },
  { name: "November" },
  { name: "December" },
];

const Export2ExcelDialog = ({ state, dataset, onClose }) => {
  const field_width = "138";
  const { hoc } = useHoc();
  console.log("expstate", state);

  const { handleSubmit, control } = useForm({
    defaultValues: {
      ...state,
    },
  });

  //console.log("jobstate",state)
  const onSubmit = (values) => {
    <Export2Excel filename="hoc" dataset={hoc} title="Hoc" />;
  };

  const handleClose = () => {
    onClose();
  };

  // useEffect(() => {
  //   setState(initial_state);
  //   setState({ ...formdata });
  //   setState({ ...formdata });
  //   console.log("laeve form",state)
  // }, [initialValues]);

  return (
    <Box>
      <Box p={2}>
        <Heading size="md">EXPORT TO EXCEL DIALOG</Heading>
      </Box>
      {/* <Box>
        <Export2Excel filename="hoc" dataset={hoc} title="Hoc" />
      </Box> */}
      <Divider />

      <form onSubmit={handleSubmit(onSubmit)}>
        <div>
          <FormControl>
            <Controller
              control={control}
              name="type"
              defaultValue={state.type}
              render={({ field: { onChange, value, ref } }) => (
                <InputGroup>
                  <HStack w="100%" py={1}>
                    <InputLeftAddon children="Type" minWidth={field_width} />
                    <Input
                      name="type"
                      value={value}
                      width="full"
                      onChange={onChange}
                      borderColor="gray.400"
                      isReadOnly
                      //textTransform="capitalize"
                      ref={ref}
                      placeholder="type"
                    />
                  </HStack>
                </InputGroup>
              )}
            />
          </FormControl>
        </div>
        <div>
          <FormControl>
            <Controller
              control={control}
              name="month"
              defaultValue={state.month}
              render={({ field: { onChange, value, ref } }) => (
                <InputGroup>
                  <HStack w="100%" py={1}>
                    <InputLeftAddon children="Month" minWidth={field_width} />
                    <Select
                      name="month"
                      value={value}
                      width="full"
                      onChange={onChange}
                      borderColor="gray.400"
                      //textTransform="capitalize"
                      ref={ref}
                      //placeholder="category"
                    >
                      {months &&
                        months.map((rec, index) => {
                          return (
                            <option key={rec.index} value={rec.name}>
                              {rec.name}
                            </option>
                          );
                        })}
                    </Select>
                  </HStack>
                </InputGroup>
              )}
            />
          </FormControl>
        </div>
        <div>
          <FormControl>
            <Controller
              control={control}
              name="year"
              defaultValue={state.year}
              render={({ field: { onChange, value, ref } }) => (
                <InputGroup>
                  <HStack w="100%" py={1}>
                    <InputLeftAddon children="Year" minWidth={field_width} />
                    <Select
                      name="year"
                      value={value}
                      width="full"
                      onChange={onChange}
                      borderColor="gray.400"
                      //textTransform="capitalize"
                      ref={ref}
                      //placeholder="category"
                    >
                      <option value="2021">2021</option>
                      <option value="2022">2022</option>
                    </Select>
                  </HStack>
                </InputGroup>
              )}
            />
          </FormControl>
        </div>
        <div>
          <FormControl>
            <Controller
              control={control}
              name="title"
              defaultValue={state.title}
              render={({ field: { onChange, value, ref } }) => (
                <InputGroup>
                  <HStack w="100%" py={1}>
                    <InputLeftAddon children="Title" minWidth={field_width} />
                    <Input
                      name="title"
                      value={value}
                      width="full"
                      onChange={onChange}
                      borderColor="gray.400"
                      ref={ref}
                      placeholder="title"
                    />
                  </HStack>
                </InputGroup>
              )}
            />
          </FormControl>
        </div>
        <div>
          <FormControl>
            <Controller
              control={control}
              name="filename"
              defaultValue={state.filename}
              render={({ field: { onChange, value, ref } }) => (
                <InputGroup>
                  <HStack w="100%" py={1}>
                    <InputLeftAddon
                      children="Filename"
                      minWidth={field_width}
                    />
                    <Input
                      name="filename"
                      value={value}
                      width="full"
                      onChange={onChange}
                      borderColor="gray.400"
                      ref={ref}
                      placeholder="filename"
                    />
                  </HStack>
                </InputGroup>
              )}
            />
          </FormControl>
        </div>
        <Box>
        <Export2Excel filename="hoc" dataset={hoc} title={state.title} />
      </Box>
        {/* <div>
          <Button
            type="submit"
            colorScheme="teal"
            variant="solid"
            onClick={handleSubmit(onSubmit)}
          >
            Download
          </Button>
        </div> */}
      </form>
    </Box>
  );
};

export default Export2ExcelDialog;
